async def main(args: Args) -> Output:
    import re

    params = args.params
    content = str(params.get('content') or '').strip()
    if not content:
        return {"texts": ""}

    text = re.sub(r'[“”‘’"\'\[\]()（）/\\《》]+', '', content)
    text = re.sub(r'[\r\n]+', '', text)
    text = re.sub(r'\s+', '', text)

    connectors = [
        '但是', '可是', '不过', '因为', '所以', '于是', '然后', '后来', '同时',
        '而且', '并且', '如果', '虽然', '其实', '比如', '尤其', '再说', '再看',
        '很多人只知道', '你以为', '真正', '更狠的是', '可这还没完',
        '直到', '自此', '从那以后', '也正因如此'
    ]

    def find_cut_position(piece, target=18):
        piece = str(piece or '')
        if len(piece) <= target + 3:
            return len(piece)

        candidate_positions = []
        for m in re.finditer(r'[，、：:；;]', piece):
            pos = m.start()
            if 6 <= pos <= target + 4:
                candidate_positions.append((abs(pos - target), pos))
        for word in connectors:
            idx = piece.find(word, 5)
            while idx != -1:
                if 6 <= idx <= target + 4:
                    candidate_positions.append((abs(idx - target) + 0.5, idx))
                idx = piece.find(word, idx + len(word))

        if candidate_positions:
            candidate_positions.sort(key=lambda x: (x[0], -x[1]))
            return candidate_positions[0][1]

        fallback = min(max(target, 8), len(piece))
        return fallback

    def split_piece(piece, target=18):
        piece = str(piece or '').strip('，、：:；; ')
        if not piece:
            return []

        clauses = [p.strip('，、：:；; ') for p in re.split(r'[，、：:；;]', piece) if p and p.strip('，、：:；; ')]
        if not clauses:
            clauses = [piece]

        merged = []
        current = ''
        for clause in clauses:
            if not current:
                current = clause
                continue
            if len(current) + len(clause) <= target:
                current = f"{current}，{clause}"
            else:
                merged.append(current)
                current = clause
        if current:
            merged.append(current)

        final_chunks = []
        for chunk in merged:
            chunk = chunk.strip('，、：:；; ')
            while len(chunk) > target + 3:
                cut = find_cut_position(chunk, target)
                head = chunk[:cut].strip('，、：:；; ')
                tail = chunk[cut:].strip('，、：:；; ')
                if head:
                    final_chunks.append(head)
                chunk = tail
            if chunk:
                final_chunks.append(chunk)

        refined = []
        for chunk in final_chunks:
            if refined and len(chunk) <= 4:
                refined[-1] = f"{refined[-1]}，{chunk}"
            else:
                refined.append(chunk)
        return refined

    sentence_pieces = [p for p in re.split(r'[。！？；.!?;]+', text) if p and p.strip()]
    items = []
    for piece in sentence_pieces:
        items.extend(split_piece(piece, target=18))

    if not items:
        items = split_piece(text, target=18) or [content]

    return {"texts": "\n".join(items)}

import re

def normalize_myth_terms(text):
    value = str(text or '')
    replacements = {
        '历节': '历劫',
        '节数': '劫数',
        '节难': '劫难',
    }
    for wrong, correct in replacements.items():
        value = value.replace(wrong, correct)
    return value

def clean_caption_text(text):
    value = normalize_myth_terms(text).strip()
    if not value:
        return ''
    value = re.sub(r'[“”‘’"\'《》\[\]()（）/\\]+', '', value)
    value = re.sub(r'[，,。！？!?；;、：:…]+', ' ', value)
    value = re.sub(r'\s+', ' ', value).strip()
    return value

async def main(args: Args) -> Output:
    params = args.params
    def _as_list(v):
        if isinstance(v, (list, tuple)):
            return list(v)
        if isinstance(v, str):
            return [item.strip() for item in v.splitlines() if item and item.strip()]
        return []
    def _normalize_text_list(v):
        out = []
        for item in _as_list(v):
            cleaned = clean_caption_text(item)
            if cleaned:
                out.append(cleaned)
        return out
    captions = _as_list(params.get('caption_list'))
    audios = _as_list(params.get('audio_list'))
    images = _as_list(params.get('image_list'))
    videos = _as_list(params.get('video_list'))
    timelines = _as_list(params.get('timelines'))
    source_texts = _normalize_text_list(params.get('source_texts'))
    texts = _normalize_text_list(params.get('texts'))
    aligned_texts = texts or source_texts
    audio = params.get('audio')
    duration = float(params.get('duration') or 0)
    image_url = params.get('image_url')
    pre_time = int(params.get('pre_time') or 0)
    segment_duration = max(int(duration * 1000000), 0)
    if audio and segment_duration > 0:
        audios.append({
            "audio_url": audio,
            "duration": segment_duration,
            "start": pre_time,
            "end": pre_time + segment_duration,
        })
    primary = str(image_url or '').strip()
    scene_image = primary if primary else '__MISSING_SCENE_IMAGE__'
    videos.append('')
    images.append(scene_image)
    for index2, obj in enumerate(timelines):
        if not isinstance(obj, dict):
            continue
        start = obj.get('start')
        end = obj.get('end')
        if index2 < len(aligned_texts):
            text = aligned_texts[index2]
        elif index2 < len(source_texts):
            text = source_texts[index2]
        else:
            text = ''
        if start is None or end is None or not text:
            continue
        start_at = int(pre_time + start)
        end_at = int(pre_time + end)
        if end_at <= start_at:
            continue
        captions.append({
            'text': text,
            'start': start_at,
            'end': end_at,
        })
    return {
        "captions": captions,
        "audios": audios,
        "images": images,
        "videos": videos,
        "end_time": pre_time + segment_duration
    }

import re

_SENT_RE = re.compile(r'(?<=[。！？\n])')
_CLAUSE_RE = re.compile(r'(?<=[，,；;。！？!?、])')


def _split_content_list(items, count):
    if not isinstance(items, (list, tuple)):
        try:
            import json as _j
            items = _j.loads(str(items))
        except Exception:
            items = [str(items)] if items else []
    if not isinstance(items, list):
        items = list(items) if items else []
    count = max(int(count or 8), 1)
    if len(items) == count:
        return items
    full = ''.join(str(x) for x in items).strip()
    if not full:
        return items
    parts = [p.strip() for p in _SENT_RE.split(full) if p.strip()]
    if len(parts) < 3:
        parts = [p.strip() for p in _CLAUSE_RE.split(full) if p.strip()]
    if len(parts) <= 1:
        if count <= 1:
            return items
        full_text = str(full).strip()
        if not full_text:
            return items
        chunk_size = max(len(full_text) // count, 1)
        rough_segments = []
        start = 0
        for seg in range(count):
            end = len(full_text) if seg == count - 1 else min(len(full_text), start + chunk_size)
            piece = full_text[start:end].strip()
            if piece:
                rough_segments.append(piece)
            start = end
        return rough_segments if rough_segments else items
    target = min(count, len(parts))
    avg = len(parts) / target
    segments = []
    i = 0
    for seg in range(target):
        end_idx = len(parts) if seg == target - 1 else int((seg + 1) * avg)
        chunk = ''.join(parts[i:end_idx]).strip()
        if chunk:
            segments.append(chunk)
        i = end_idx
    return segments if segments else items


def _seconds_to_us(value, minimum=0):
    try:
        num = float(value or 0)
    except Exception:
        num = 0
    return max(int(num * 1000000), int(minimum or 0))


async def main(args: Args) -> Output:
    params = args.params

    intro_link = str(params.get('link') or '').strip()
    title_link = str(params.get('title_link') or '').strip()
    intro_us = _seconds_to_us(params.get('duration'), 1800000 if intro_link else 0)
    title_us = _seconds_to_us(params.get('title_duration'), 1200000 if title_link else 0)
    gap_after_intro = 0
    gap_after_title = 300000

    audios = []
    cursor = 0
    if intro_link and intro_us > 0:
        audios.append({
            'audio_url': intro_link,
            'duration': intro_us,
            'start': cursor,
            'end': cursor + intro_us,
        })
        cursor += intro_us + gap_after_intro

    if title_link and title_us > 0:
        audios.append({
            'audio_url': title_link,
            'duration': title_us,
            'start': cursor,
            'end': cursor + title_us,
        })
        cursor += title_us

    next_duration = cursor + gap_after_title

    images = []

    content_list = params.get('content_list') or []
    shuliang = params.get('shuliang') or 8
    content_items = _split_content_list(content_list, shuliang)
    content_items = [x for x in content_items if str(x or '').strip()]

    if content_items:
        content_items[0] = re.sub(r'^(今天(为大家|给大家|我们|咱们?)?(介绍|讲|说|认识)(的是)?[，,：: ]*)', '', str(content_items[0])).strip()
        if not content_items[0]:
            content_items = content_items[1:]

    def _strip_tail_punct(s):
        s = str(s or '').strip()
        if not s:
            return s
        return re.sub(r'[。！？!?]+\s*$', '', s).strip()

    content_items = [_strip_tail_punct(x) for x in content_items]
    content_items = [x for x in content_items if x]

    try:
        shuliang_int = max(int(shuliang or 8), 1)
    except Exception:
        shuliang_int = 8
    if len(content_items) > shuliang_int:
        content_items = content_items[:shuliang_int]

    return {
        'audios': audios,
        'images': images,
        'duration': intro_us,
        'nextDuration': next_duration,
        'content_items': content_items,
        'captions': [],
        'videos': [],
    }

