async def main(args: Args) -> Output:
    params = getattr(args, 'params', None) or {}
    raw = params.get('titleFrameImages') or '[]'

    try:
        items = json.loads(raw) if isinstance(raw, str) else list(raw)
    except Exception:
        items = []

    if not isinstance(items, list):
        items = []

    output = []
    for item in items:
        if not isinstance(item, dict):
            continue
        obj = dict(item)
        original_start = int(obj.get('start', 0) or 0)
        original_end = int(obj.get('end', original_start) or original_start)
        if original_end > original_start:
            obj['end'] = 5000000
        obj['start'] = 0
        obj['transform_x'] = -42
        obj['transform_y'] = 96
        obj['scale_x'] = 0.43
        obj['scale_y'] = 0.31
        output.append(obj)

    return {
        'image_infos': json.dumps(output, ensure_ascii=False)
    }

async def main(args: Args) -> Output:
    _p = getattr(args, "params", None) or {}
    raw = str(_p.get("prompt_in") or "").strip()
    max_len = 640
    if len(raw) <= max_len:
        out = raw
    else:
        cut = raw[:max_len]
        out = cut
        for sep in ("。", "，", ",", ";", "；", "\n", "、"):
            i = cut.rfind(sep)
            if i > int(max_len * 0.55):
                out = cut[: i + 1].strip()
                break
    if len(out) > max_len:
        out = out[:max_len].strip()
    return {"prompt_out": out}

