import json


def ensure_list(value):
    if isinstance(value, str):
        try:
            value = json.loads(value)
        except Exception:
            value = []
    if not isinstance(value, list):
        value = []
    return value


def add_scale_pop_keyframes(keyframes, segments):
    for seg in segments:
        if not isinstance(seg, dict):
            continue
        segment_id = str(seg.get('id') or '').strip()
        start = int(seg.get('start') or 0)
        end = int(seg.get('end') or start)
        if not segment_id or end <= start:
            continue
        keyframes.append({
            'offset': start,
            'property': 'UNIFORM_SCALE',
            'segment_id': segment_id,
            'value': 5.0,
        })
        keyframes.append({
            'offset': end,
            'property': 'UNIFORM_SCALE',
            'segment_id': segment_id,
            'value': 1.0,
        })


def add_image_pan_keyframes(keyframes, segments):
    pan_cycle = [
        {'sx': -54, 'sy': -16, 'ex': 38, 'ey': -4, 'ss': 1.16, 'es': 1.08},
        {'sx': 52, 'sy': 14, 'ex': -32, 'ey': -10, 'ss': 1.18, 'es': 1.1},
        {'sx': -22, 'sy': -38, 'ex': 24, 'ey': 4, 'ss': 1.14, 'es': 1.06},
        {'sx': 40, 'sy': -12, 'ex': -42, 'ey': 18, 'ss': 1.2, 'es': 1.1},
        {'sx': -36, 'sy': 28, 'ex': 30, 'ey': -16, 'ss': 1.15, 'es': 1.07},
        {'sx': 24, 'sy': -30, 'ex': -24, 'ey': 20, 'ss': 1.13, 'es': 1.05},
    ]
    for idx, seg in enumerate(segments):
        if not isinstance(seg, dict):
            continue
        segment_id = str(seg.get('id') or '').strip()
        start = int(seg.get('start') or 0)
        end = int(seg.get('end') or start)
        if not segment_id or end <= start:
            continue
        motion = pan_cycle[idx % len(pan_cycle)]
        keyframes.append({
            'offset': start,
            'property': 'KFTypePositionX',
            'segment_id': segment_id,
            'value': motion['sx'],
        })
        keyframes.append({
            'offset': end,
            'property': 'KFTypePositionX',
            'segment_id': segment_id,
            'value': motion['ex'],
        })
        keyframes.append({
            'offset': start,
            'property': 'KFTypePositionY',
            'segment_id': segment_id,
            'value': motion['sy'],
        })
        keyframes.append({
            'offset': end,
            'property': 'KFTypePositionY',
            'segment_id': segment_id,
            'value': motion['ey'],
        })
        keyframes.append({
            'offset': start,
            'property': 'UNIFORM_SCALE',
            'segment_id': segment_id,
            'value': motion['ss'],
        })
        keyframes.append({
            'offset': end,
            'property': 'UNIFORM_SCALE',
            'segment_id': segment_id,
            'value': motion['es'],
        })


async def main(args: Args) -> Output:
    params = getattr(args, 'params', None) or {}
    segment_infos = ensure_list(params.get('segment_infos'))
    segment_infos_b = ensure_list(params.get('segment_infos_b'))
    segment_infos_c = ensure_list(params.get('segment_infos_c'))
    image_segment_infos = ensure_list(params.get('image_segment_infos'))

    keyframes = []
    add_scale_pop_keyframes(keyframes, segment_infos)
    add_scale_pop_keyframes(keyframes, segment_infos_b)
    add_scale_pop_keyframes(keyframes, segment_infos_c)
    add_image_pan_keyframes(keyframes, image_segment_infos)

    return {
        'keyframes': json.dumps(keyframes, ensure_ascii=False)
    }
